insert into public.questions
  (subject_id, lecture_id, tag, stem, option_a, option_b, option_c, option_d, option_e, answer, explanation, image_url)
values
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Stopping life support in accordance with patient wishes is physician-assisted suicide.', 'True', 'False', '', '', '', 1, 'Withdrawing ongoing treatment is allowing natural death, not physician-assisted suicide.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'A family insists on continuing life support despite a patient''s documented refusal; the physician should follow the family''s wishes.', 'True', 'False', '', '', '', 1, 'Respect patient autonomy and withdraw treatment according to the patient''s wishes.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'The situation shown in the image is an example of physician-assisted suicide.', 'True', 'False', '', '', '', 1, 'It is euthanasia, because the doctor actively causes death.', 'data:image/jpeg;base64,'),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'A terminal cancer patient who previously refused life support may have ventilation ethically and legally withdrawn.', 'True', 'False', '', '', '', 0, 'The patient''s prior wishes must be respected, even if they are now incapacitated.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Withdrawal of treatment is ethically controversial and illegal in most countries.', 'True', 'False', '', '', '', 1, 'Withdrawal of treatment is not euthanasia; it allows natural death while respecting the patient''s wishes.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Withdrawing treatment means not starting treatment.', 'True', 'False', '', '', '', 1, 'Withholding treatment means not starting treatment; withdrawal is stopping treatment already begun.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'If a patient''s wishes are unclear, the family can act as surrogate decision-makers.', 'True', 'False', '', '', '', 0, 'Surrogates help make decisions when the patient''s wishes are unknown.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Giving high-dose opioids for symptom relief that may unintentionally shorten life is NOT an example of the doctrine of double effect.', 'True', 'False', '', '', '', 1, 'It IS an example of the doctrine of double effect.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'In euthanasia, the doctor''s role is to provide the means for the patient to end their own life.', 'True', 'False', '', '', '', 1, 'That describes physician-assisted suicide; in euthanasia the doctor performs the final act.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'A physician directly administering a lethal injection that causes the patient''s death is an example of euthanasia.', 'True', 'False', '', '', '', 0, 'The doctor performs the final act that causes death.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'A physician prescribing lethal medication that the patient takes themselves is an example of euthanasia.', 'True', 'False', '', '', '', 1, 'This is physician-assisted suicide; the patient performs the final act, not the doctor.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Autonomy means acting in the patient''s best interest.', 'True', 'False', '', '', '', 1, 'Acting in the patient''s best interest is beneficence.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Beneficence means avoiding harm.', 'True', 'False', '', '', '', 1, 'Avoiding harm is non-maleficence.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Justice means respecting the patient as a person.', 'True', 'False', '', '', '', 1, 'Respecting the patient as a person is dignity.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Beneficence means acting in the patient''s best interest.', 'True', 'False', '', '', '', 0, 'This is the definition of beneficence.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'A DNR order means pain relief should be discontinued.', 'True', 'False', '', '', '', 1, 'A DNR order does not stop care: comfort care and pain relief continue.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'A DNR order means no CPR if cardiac or respiratory arrest occurs.', 'True', 'False', '', '', '', 0, 'DNR stands for Do Not Resuscitate.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Palliative care cannot be provided alongside curative treatment.', 'True', 'False', '', '', '', 1, 'Palliative care can be provided with or without curative treatment.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'The goal of end-of-life care is to provide comfort, dignity, and quality of life.', 'True', 'False', '', '', '', 0, 'It applies to terminal illness, irreversible conditions, and advanced chronic disease.', ''),
  ('ethics', 'et-10', 'End-of-Life Ethics', 'Life-sustaining treatments include mechanical ventilation, CPR, dialysis, and artificial nutrition and hydration.', 'True', 'False', '', '', '', 0, 'All of these are examples of life-sustaining treatment.', '');
